 frankensearch-migration = ["dep:frankensearch-core", "dep:frankensearch-fusion", "dep:frankensearch-index", "dep:frankensearch-embed", "dep:asupersync"]

+# frankensearch currently wires asupersync through a workspace path outside the
+# frankensearch git checkout, which can resolve inconsistently on remote workers.
+# Force all asupersync requests coming from that source to the canonical repo.
+[patch."https://github.com/Dicklesworthstone/frankensearch.git"]
+asupersync = { git = "https://github.com/Dicklesworthstone/asupersync.git", rev = "22505d891736f59098607aaeb4a55149208f7b70" }
